# ArticleCardBySlug

## Purpose

A React Router `.tsx` component that resolves an article from the local articles registry by `slug` and renders an `ArticleCard`. It formats the publication date, resolves author details, and supplies a fallback image.

## File

`app/components/article-card-by-slug.tsx`

## Props

| Prop | Type | Default | Description |
|---|---|---|---|
| `slug` | `string` | — | Article slug to look up in the registry. |
| `ctaText` | `string` | `'Read more'` | Text shown for the article link. |
| `className` | `string` | — | Additional classes passed to `ArticleCard`. |
| `descriptionOverride` | `string` | — | Replaces the registry description. |
| `variant` | `'default' \| 'compact'` | `'default'` | Card size variant. |
| `authorOverride` | `Author` | — | Replaces the resolved registry author. |

## Semantic Hints

`card`, `article-card`, `slug-card`, `dynamic-card`, `registry-card`, `auto-card`

## Behavior

1. Finds the article in `articles` using `slug`.
2. Resolves the article author from `authors` when `authorId` is present.
3. Uses `descriptionOverride` and `authorOverride` when supplied.
4. Formats `publishedAt` with `Intl.DateTimeFormat`.
5. Uses a fallback image when the article has no image.
6. Returns `null` and logs a warning when no article matches the slug.
7. Renders a React Router `Link` to `/articles/:slug`.

## Implementation

```tsx
import { Link } from "react-router";

export type Author = {
  name: string;
  avatarUrl?: string;
};

type Article = {
  slug: string;
  title: string;
  description: string;
  image?: string;
  publishedAt: string;
  authorId?: string;
};

const authors: Record<string, Author> = {
  "jane-doe": { name: "Jane Doe" },
};

const articles: Article[] = [
  {
    slug: "machine-learning-basics",
    title: "Machine Learning Basics",
    description: "An introduction to core machine learning concepts.",
    publishedAt: "2025-01-15",
    authorId: "jane-doe",
  },
];

const fallbackImage = "/images/article-placeholder.jpg";

type ArticleCardBySlugProps = {
  slug: string;
  ctaText?: string;
  className?: string;
  descriptionOverride?: string;
  variant?: "default" | "compact";
  authorOverride?: Author;
};

export function ArticleCardBySlug({
  slug,
  ctaText = "Read more",
  className,
  descriptionOverride,
  variant = "default",
  authorOverride,
}: ArticleCardBySlugProps) {
  const article = articles.find((item) => item.slug === slug);

  if (!article) {
    console.warn(`ArticleCardBySlug: article not found for slug "${slug}"`);
    return null;
  }

  const author = authorOverride ?? (
    article.authorId ? authors[article.authorId] : undefined
  );

  const formattedDate = new Intl.DateTimeFormat("en", {
    dateStyle: "medium",
  }).format(new Date(article.publishedAt));

  return (
    <article
      className={[
        "overflow-hidden rounded-lg border border-slate-200",
        variant === "compact" ? "p-4" : "p-6",
        className,
      ].filter(Boolean).join(" ")}

